const crypto = require('crypto');

// Get webhook data
const item = $input.first();
const body = item.json.body || {};

// Validation
const errors = [];
const spamKeywords = ['viagra', 'casino', 'lottery', 'winner', 'click here', 'free money'];

// Required fields
if (!body.name || body.name.trim() === '') errors.push('Missing name');
if (!body.email || body.email.trim() === '') errors.push('Missing email');
if (!body.message || body.message.trim() === '') errors.push('Missing message');
if (!body.product || body.product.trim() === '') errors.push('Missing product');

// Email validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (body.email && !emailRegex.test(body.email)) {
  errors.push('Invalid email format');
}

// Spam detection
const messageText = (body.message || '').toLowerCase();
const hasSpam = spamKeywords.some(keyword => messageText.includes(keyword));
if (hasSpam) errors.push('Spam keywords detected');

// Check for suspicious patterns
if (body.message && body.message.length > 5000) {
  errors.push('Message too long (possible spam)');
}

// Enrich: company from email domain if not provided
let company = body.company || '';
if (!company && body.email) {
  const domain = body.email.split('@')[1];
  if (domain && !['gmail.com', 'yahoo.com', 'hotmail.com', 'outlook.com'].includes(domain)) {
    company = domain.split('.')[0];
  }
}

// Generate unique ID for idempotency
const idempotencyKey = crypto.createHash('md5')
  .update(body.email + body.message + (body.product || ''))
  .digest('hex');

// Normalize urgency
const urgency = (body.urgency || 'normal').toLowerCase();

return [{
  json: {
    id: idempotencyKey,
    name: body.name,
    email: body.email,
    company: company,
    message: body.message,
    urgency: urgency === 'high' ? 'high' : 'normal',
    product: body.product,
    timestamp: new Date().toISOString(),
    isValid: errors.length === 0,
    errors: errors
  }
}];

const items = $input.all();
const today = new Date();
today.setHours(0, 0, 0, 0);

const todayLeads = items.filter(item => {
  const timestamp = new Date(item.json.Timestamp);
  timestamp.setHours(0, 0, 0, 0);
  return timestamp.getTime() === today.getTime();
});

return todayLeads.length > 0 ? todayLeads : [{ json: {} }];

const items = $input.all();

// Count by urgency
const urgencyCounts = { high: 0, normal: 0 };
items.forEach(item => {
  const urgency = (item.json.Urgency || 'normal').toLowerCase();
  if (urgency === 'high') urgencyCounts.high++;
  else urgencyCounts.normal++;
});

// Count by product
const productCounts = {};
items.forEach(item => {
  const product = item.json.Product || 'Unknown';
  productCounts[product] = (productCounts[product] || 0) + 1;
});

// Top 5 recent leads
const sortedLeads = items
  .sort((a, b) => new Date(b.json.Timestamp) - new Date(a.json.Timestamp))
  .slice(0, 5)
  .map(item => ({
    name: item.json.Name,
    email: item.json.Email,
    company: item.json.Company || 'N/A',
    product: item.json.Product,
    urgency: item.json.Urgency
  }));

return [{
  json: {
    totalLeads: items.length,
    urgencyCounts: urgencyCounts,
    productCounts: productCounts,
    topRecentLeads: sortedLeads,
    date: new Date().toISOString().split('T')[0]
  }
}];
